--
-- Table structure for table `evidence_category`
--

DROP TABLE IF EXISTS `evidence_category`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `evidence_category` (
  `evidence_category` varchar(45) NOT NULL,
  `evidence_description` varchar(700) DEFAULT NULL,
  PRIMARY KEY (`evidence_category`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `evidence_category`
--

LOCK TABLES `evidence_category` WRITE;
/*!40000 ALTER TABLE `evidence_category` DISABLE KEYS */;
INSERT INTO `evidence_category` VALUES ('1A','Level 1A annotations describe variant-drug combinations that have variant-specific prescribing guidance available in a current clinical guideline annotation or an FDA-approved drug label annotation. Annotations of drug labels or clinical guidelines must give prescribing guidance for specific variants (e.g. CYP2C9*3, HLA-B*57:01) or provide mapping from defined allele functions to diplotypes and phenotypes to be used as supporting evidence for a level 1A summary annotation. Level 1A summary annotations must also be supported by at least one publication in addition to a clinical guideline or drug label with variant-specific prescribing guidance.'),('1B','Level 1B annotations describe variant-drug combinations with a high level of evidence supporting the association but no variant-specific prescribing guidance in an annotated clinical guideline or FDA drug label. Level 1B summary annotations must be supported by at least two independent publications.'),('2A','Variants in Level 2A annotations are variants in known pharmacogenes, implying causation of drug phenotype is more likely. These summary annotations describe variant-drug combinations with a moderate level of evidence supporting the association. For example, the association may be found in multiple cohorts, but there may be a minority of studies that do not support the majority assertion. Level 2A summary annotations must be supported by at least two independent publications.'),('2B','Variants in Level 2B annotations describe variant-drug combinations with a moderate level of evidence supporting the association. For example, the association may be found in multiple cohorts, but there may be a minority of studies that do not support the majority assertion. Level 2B summary annotations must be supported by at least two independent publications.'),('3','Level 3 annotations describe variant-drug combinations with a low level of evidence supporting the association. This association may be based on a single study annotated in ClinPGx, or there may be several studies that failed to replicate the association. The annotation may also be based on preliminary evidence (e.g., a case report, non-significant study, or in vitro, molecular, or functional assay evidence), resulting in a lower calculated score.'),('4','Level 4 annotations describe variant-drug combinations where the total score is negative and the evidence does not support an association between the variant and the drug phenotype.');
/*!40000 ALTER TABLE `evidence_category` ENABLE KEYS */;
UNLOCK TABLES;

