--
-- Table structure for table `variants_has_drugs`
--

DROP TABLE IF EXISTS `variants_has_drugs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `variants_has_drugs` (
  `id_annotation` int NOT NULL,
  `variants_variant_name` varchar(45) NOT NULL,
  `drugs_drug_name` varchar(45) NOT NULL,
  `phenotype_category_phenotype_category` varchar(45) NOT NULL,
  `illness_illness_name` varchar(45) NOT NULL,
  `evidence_category_evidence_category` varchar(45) NOT NULL,
  `URL_web` varchar(60) DEFAULT NULL,
  PRIMARY KEY (`id_annotation`),
  KEY `fk_variants_has_drugs_drugs1_idx` (`drugs_drug_name`),
  KEY `fk_variants_has_drugs_variants1_idx` (`variants_variant_name`),
  KEY `fk_variants_has_drugs_phenotype_category1_idx` (`phenotype_category_phenotype_category`),
  KEY `fk_variants_has_drugs_illness1_idx` (`illness_illness_name`),
  KEY `fk_variants_has_drugs_evidence_category1_idx` (`evidence_category_evidence_category`),
  CONSTRAINT `fk_drugs1` FOREIGN KEY (`drugs_drug_name`) REFERENCES `drugs` (`drug_name`),
  CONSTRAINT `fk_evidence_category1` FOREIGN KEY (`evidence_category_evidence_category`) REFERENCES `evidence_category` (`evidence_category`),
  CONSTRAINT `fk_illness1` FOREIGN KEY (`illness_illness_name`) REFERENCES `illness` (`illness_name`),
  CONSTRAINT `fk_phenotype_category1` FOREIGN KEY (`phenotype_category_phenotype_category`) REFERENCES `phenotype_category` (`phenotype_category`),
  CONSTRAINT `fk_variants1` FOREIGN KEY (`variants_variant_name`) REFERENCES `variants` (`variant_name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;
/*!40101 SET character_set_client = @saved_cs_client */;

